svg.script:

const boardTiles = document.getElementById('board-tiles');
const scoreEl = document.getElementById('score');
const overlay = document.getElementById('overlay');

let score = 0;
let grid = Array(4).fill().map(() => Array(4).fill(0));
let gameActive = false;
let tileObjects = [];

const COLORS = {
    0: "#B9A189", 2: "#eee4da", 4: "#ede0c8", 8: "#f2b179", 16: "#f59563",
    32: "#f67c5f", 64: "#f65e3b", 128: "#f2b982", 256: "#f2b982", 512: "#f2b982",
    1024: "#f2b982", 2048: "#edc22e"
};

function createBoard() {
    boardTiles.innerHTML = '';
    tileObjects = [];
    for (let r = 0; r < 4; r++) {
        for (let c = 0; c < 4; c++) {
            // Use a Group for each tile and move the group
            const g = document.createElementNS("http://www.w3.org/2000/svg", "g");
            const tx = 10 + c * 100;
            const ty = 10 + r * 100;
            g.setAttribute('transform', `translate(${tx}, ${ty})`);

            const rect = document.createElementNS("http://www.w3.org/2000/svg", "rect");
            rect.setAttribute('x', '0');
            rect.setAttribute('y', '0');
            rect.setAttribute('width', '90');
            rect.setAttribute('height', '90');
            rect.setAttribute('rx', '5');
            rect.setAttribute('fill', COLORS[0]);

            const text = document.createElementNS("http://www.w3.org/2000/svg", "text");
            text.setAttribute('x', '45');
            text.setAttribute('y', '45');
            text.setAttribute('text-anchor', 'middle');
            text.setAttribute('dominant-baseline', 'central');
            text.setAttribute('font-weight', 'bold');
            text.setAttribute('font-size', '40');
            text.setAttribute('fill', '#776e65');
            text.textContent = '';

            g.appendChild(rect);
            g.appendChild(text);
            boardTiles.appendChild(g);
            tileObjects.push({rect, text});
        }
    }
}

function addRandomTile() {
    const empty = [];
    for (let r = 0; r < 4; r++)
        for (let c = 0; c < 4; c++)
            if (grid[r][c] === 0) empty.push({r, c});
    if (empty.length > 0) {
        const {r, c} = empty[Math.floor(Math.random() * empty.length)];
        grid[r][c] = Math.random() < 0.9 ? 2 : 4;
    }
}

function updateView() {
    for (let r = 0; r < 4; r++) {
        for (let c = 0; c < 4; c++) {
            const val = grid[r][c];
            const tile = tileObjects[r * 4 + c];
            tile.rect.setAttribute('fill', COLORS[val] || '#3c3c3c');
            tile.text.textContent = val === 0 ? '' : val;
            tile.text.setAttribute('fill', val <= 4 ? '#776e65' : 'white');
            tile.text.setAttribute('font-size', val >= 100 ? '30' : '40');
        }
    }
    scoreEl.textContent = score;
}

function slide(row) {
    let filtered = row.filter(v => v !== 0);
    for (let i = 0; i < filtered.length - 1; i++) {
        if (filtered[i] === filtered[i+1]) {
            filtered[i] *= 2;
            score += filtered[i];
            filtered.splice(i + 1, 1);
        }
    }
    while (filtered.length < 4) filtered.push(0);
    return filtered;
}

function move(dir) {
    if (!gameActive) return;
    const prev = JSON.stringify(grid);

    if (dir === 'ArrowLeft') {
        for (let r = 0; r < 4; r++) grid[r] = slide(grid[r]);
    } else if (dir === 'ArrowRight') {
        for (let r = 0; r < 4; r++) grid[r] = slide(grid[r].slice().reverse()).reverse();
    } else if (dir === 'ArrowUp') {
        for (let c = 0; c < 4; c++) {
            let col = [grid[0][c], grid[1][c], grid[2][c], grid[3][c]];
            col = slide(col);
            for (let r = 0; r < 4; r++) grid[r][c] = col[r];
        }
    } else if (dir === 'ArrowDown') {
        for (let c = 0; c < 4; c++) {
            let col = [grid[3][c], grid[2][c], grid[1][c], grid[0][c]];
            col = slide(col);
            for (let r = 0; r < 4; r++) grid[3-r][c] = col[r];
        }
    }

    if (JSON.stringify(grid) !== prev) {
        addRandomTile();
        updateView();
    }

    if (!canMove()) {
        gameActive = false;
        overlay.setAttribute('visibility', 'visible');
        overlay.querySelector('text').textContent = "GAME OVER!";
    }
}

function canMove() {
    for (let r = 0; r < 4; r++)
        for (let c = 0; c < 4; c++)
            if (grid[r][c] === 0) return true;
    for (let r = 0; r < 4; r++)
        for (let c = 0; c < 3; c++)
            if (grid[r][c] === grid[r][c+1]) return true;
    for (let c = 0; c < 4; c++)
        for (let r = 0; r < 3; r++)
            if (grid[r][c] === grid[r+1][c]) return true;
    return false;
}

window.addEventListener('keydown', (e) => {
    if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
        e.preventDefault();
        move(e.key);
    }
    if (e.key.toLowerCase() === 'r') {
        grid = Array(4).fill().map(() => Array(4).fill(0));
        score = 0;
        gameActive = true;
        overlay.setAttribute('visibility', 'hidden');
        addRandomTile(); addRandomTile();
        updateView();
    }
});

overlay.addEventListener('click', () => {
    gameActive = true;
    overlay.setAttribute('visibility', 'hidden');
    addRandomTile(); addRandomTile();
    updateView();
});

createBoard();
updateView();
